//! Gate 4 — golden stability. A fixed, fully-populated `VmState` must encode to
//! a byte-for-byte recorded vector. Any layout change fails this test and must
//! consciously update the golden **and** bump `VM_STATE_VERSION`.

mod common;

use common::fully_populated;
use vm_state::VmState;

/// The recorded encoding of [`fully_populated`], lowercase hex. Regenerate with
/// the `print_golden` test below (run with `--ignored --nocapture`) only when a
/// format change is intentional.
const GOLDEN_HEX: &str = "";

fn to_hex(bytes: &[u8]) -> String {
    let mut s = String::with_capacity(bytes.len() * 2);
    for b in bytes {
        s.push_str(&format!("{b:02x}"));
    }
    s
}

#[test]
fn golden_encoding_is_stable() {
    let bytes = fully_populated().encode().unwrap();
    assert_eq!(
        to_hex(&bytes),
        GOLDEN_HEX,
        "vm_state encoding drifted; if intentional, update GOLDEN_HEX and bump VM_STATE_VERSION"
    );
}

#[test]
fn golden_blob_round_trips() {
    let s = fully_populated();
    let bytes = s.encode().unwrap();
    assert_eq!(VmState::decode(&bytes), Ok(s));
}

#[test]
#[ignore = "run with --ignored --nocapture to regenerate GOLDEN_HEX"]
fn print_golden() {
    let bytes = fully_populated().encode().unwrap();
    println!("GOLDEN_HEX = \"{}\"", to_hex(&bytes));
}
